20	const calculateItemSurcharges = (item: any): number => {
21	  const base = BASE_PREMIUMS[item.type] || 0;
22	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
23	  const enchantmentSurcharge =
24	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
25	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
26	      : 0;
27	  return curseSurcharge + enchantmentSurcharge;
28	};
