30	const calculateComponentsCost = (items: any[]): number => {
31	  const componentCounts: Record<string, number> = {};
32	  for (const item of items) {
33	    if (COMPONENT_TYPES.has(item.type)) {
34	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
35	    }
36	  }
37	  return Object.values(componentCounts).reduce((total, count) => {
38	    return total + (count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM);
39	  }, 0);
40	};
