42	const calculatePolicyModifiers = (basePremium: number, customer: any, quoteIndex: number): number => {
43	  let modifiers = 0;
44	  if (customer.yearsWithMHPCO >= 2) {
45	    modifiers -= basePremium * 0.2;
46	  }
47	  modifiers += basePremium * 0.1;
48	  if (quoteIndex > 0) {
49	    modifiers -= basePremium * 0.15;
50	  }
51	  return modifiers;
52	};
53	
54	const calculateQuotePremium = (items: any[], customer: any, quoteIndex: number): { premium: number } => {
55	  const equipmentItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
56	
57	  const equipmentBasePremium = equipmentItems.reduce(
58	    (sum, item) => sum + (BASE_PREMIUMS[item.type] || 0),
59	    0
